const jinaData = $input.first().json;
let jdText = jinaData.data.content || jinaData.data.description || '';
jdText = jdText.replace(/\s+/g, ' ').trim();
jdText = jdText.substring(0, 2000);

// Smart resume cleaner — handles PDF binary, docx, txt
let resume = $('Webhook').first().json.body.resume || '';

// Remove PDF binary garbage
resume = resume.replace(/%PDF[\s\S]*?(?=\n[A-Z]|\n\n)/g, '');
resume = resume.replace(/<<[\s\S]*?>>/g, '');
resume = resume.replace(/\b(obj|endobj|stream|endstream|xref|trailer|startxref)\b/g, '');
resume = resume.replace(/[^\x20-\x7E\n\r]/g, ' ');
resume = resume.replace(/\s+/g, ' ').trim();
resume = resume.substring(0, 1500);

const jobUrl = $('Webhook').first().json.body.job_url;

return [{
  json: {
    jd_text: jdText,
    resume: resume,
    job_url: jobUrl
  }
}];

