// Safely get content from each node
function getContent(nodeName) {
  try {
    return $('nodeName').first().json.choices[0].message.content || '';
  } catch(e) { return 'Not available'; }
}

const resume = $('Resume Tailor').first().json.choices[0].message.content || '';
const coverLetter = $('Cover Letter').first().json.choices[0].message.content || '';
const interviewQnA = $('Interview QnA').first().json.choices[0].message.content || '';
const companyResearch = $('Company Research').first().json.choices[0].message.content || '';
const profileMatch = $('Profile Match').first().json.choices[0].message.content || '';
const jobUrl = $('Code in JavaScript').first().json.job_url || '';

const html = `<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8"/>
<style>
  body{font-family:Arial,sans-serif;margin:40px;color:#1a1a1a;font-size:14px}
  h1{color:#2563eb;border-bottom:3px solid #2563eb;padding-bottom:10px;font-size:22px}
  h2{color:#1e40af;background:#eff6ff;padding:10px;border-radius:6px;margin-top:28px;font-size:16px}
  p{line-height:1.8;white-space:pre-wrap;margin-top:10px}
  .section{margin-bottom:24px;border:1px solid #e2e8f0;border-radius:8px;padding:18px}
  .header{text-align:center;margin-bottom:32px}
  .meta{color:#6b7280;font-size:12px;margin-top:4px}
</style>
</head>
<body>
<div class="header">
  <h1>Job Application Package</h1>
  <p class="meta">Job: ${jobUrl}</p>
  <p class="meta">Generated: ${new Date().toLocaleDateString('en-IN',{year:'numeric',month:'long',day:'numeric'})}</p>
</div>

<div class="section">
  <h2>📊 Profile Match Score</h2>
  <p>${profileMatch}</p>
</div>

<div class="section">
  <h2>🏢 Company Research</h2>
  <p>${companyResearch}</p>
</div>

<div class="section">
  <h2>📄 Tailored Resume Bullets</h2>
  <p>${resume}</p>
</div>

<div class="section">
  <h2>✉️ Cover Letter</h2>
  <p>${coverLetter}</p>
</div>

<div class="section">
  <h2>🎯 Interview Q&A Prep</h2>
  <p>${interviewQnA}</p>
</div>
</body>
</html>`;

return [{ json: { html_content: html } }];
